function searchPapers(query) {
    var q = query.toLowerCase();
    var kw = q.split(/\s+/).filter(function(k){return k.length>2;});
    return PAPERS_DB.map(function(p){
        var t = (p.abstract+' '+p.journal+' '+p.id).toLowerCase();
        var score = kw.reduce(function(s,k){return s+(t.indexOf(k)>=0?1:0);},0);
        return {id:p.id,year:p.year,journal:p.journal,abstract:p.abstract,score:score};
    }).filter(function(p){return p.score>0;})
    .sort(function(a,b){return b.score-a.score||b.year-a.year;})
    .slice(0,5);
}
